  void _insertEmojiToChat(String emoji) {
    final value = _chatController.value;
    final start = value.selection.start >= 0
        ? value.selection.start
        : value.text.length;
    final end = value.selection.end >= 0 ? value.selection.end : start;
    final newText = value.text.replaceRange(start, end, emoji);
    _chatController.value = TextEditingValue(
      text: newText,
      selection: TextSelection.collapsed(offset: start + emoji.length),
    );
  }

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _game = OkeyGame(
      tableId: widget.tableId,
      isCreator: widget.isCreator,
      onTileSfx: _playTileSfx,
      onStartDealSfx: _playStartGameSfx,
    );
    _tileSfxPlayer.setReleaseMode(jo.ReleaseMode.stop);
    _startGameSfxPlayer.setReleaseMode(jo.ReleaseMode.stop);

    _game.onHudChanged = () {
      if (mounted) setState(() {});
    };
    _game.onIndicatorBonusAwarded = _showIndicatorRewardFxBanner;

    _game.onFinish = () async {
      if (_showFinish) return; // ğŸ”¥ double trigger engelle

      setState(() {
        _showFinish = true;
      });

      _autoCloseFinish();
    };

    _myUserId = _supabase.auth.currentUser?.id;
    _prepareVoiceCoachmark();
    _bootstrap();
    _loadChatMessages();
    _subscribeRealtime();
    _ticker = Timer.periodic(const Duration(milliseconds: 150), (_) {
      if (mounted) {
        setState(() {});
      }
    });
    _tablePoll = Timer.periodic(const Duration(seconds: 1), (_) {
      _loadTable();
    });
    _playersPoll = Timer.periodic(const Duration(seconds: 1), (_) {
      _loadPlayers();
    });
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _prepareVisuals();
    });
    _hourglassCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 900),
    )..repeat(reverse: true);
    _voiceCommands.addListener(_onVoiceCommandsChanged);
    _voiceCommands.initialize();
  }

  void _onVoiceCommandsChanged() {
    if (!mounted) return;
    final hasFeedback = _voiceCommands.feedback != null;
    if (hasFeedback) {
      _voiceFeedbackTimer?.cancel();
      _voiceFeedbackTimer = Timer(const Duration(seconds: 3), () {
        if (!mounted) return;
        _voiceCommands.clearFeedback();
      });
    }
    setState(() {});
  }

  Future<void> _prepareVoiceCoachmark() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final key = '$_voiceCoachmarkKey:${_myUserId ?? 'guest'}';
      final seen = prefs.getBool(key) ?? false;
      if (!seen && mounted) {
        setState(() => _showVoiceCoachmark = true);
      }
    } catch (_) {
      // Best-effort only.
    }
  }

  Future<void> _dismissVoiceCoachmark() async {
    if (!_showVoiceCoachmark) return;
    if (mounted) {
      setState(() => _showVoiceCoachmark = false);
    }
    try {
      final prefs = await SharedPreferences.getInstance();
      final key = '$_voiceCoachmarkKey:${_myUserId ?? 'guest'}';
      await prefs.setBool(key, true);
    } catch (_) {}
  }

  Future<void> _prepareVisuals() async {
    try {
      await precacheImage(
        const AssetImage('assets/images/lobby/lobby.png'),
        context,
      );
      await precacheImage(const AssetImage('assets/images/table.png'), context);
    } catch (_) {
      // best effort
    }
    if (!mounted) return;
    setState(() => _visualReady = true);
  }

  Widget _buildTableBackdrop() {
    if (!ThemeFlags.useCinematicTheme) {
      return Image.asset('assets/images/table.png', fit: BoxFit.fill);
    }
    return AnimatedBuilder(
      animation: _hourglassCtrl,
      builder: (context, _) {
        final t = _hourglassCtrl.value;
        final pulse = 0.18 + (t * 0.12);
        return Stack(
          fit: StackFit.expand,
          children: [
            Image.asset('assets/images/table.png', fit: BoxFit.fill),
            // Ambient color pass for a more cinematic look.
            IgnorePointer(
              child: DecoratedBox(
                decoration: BoxDecoration(
                  gradient: LinearGradient(
                    begin: Alignment.topLeft,
                    end: Alignment.bottomRight,
                    colors: [
                      const Color(0xFF0F2942).withOpacity(0.26),
                      const Color(0xFF2F1D49).withOpacity(0.18),
                      const Color(0xFF112D3C).withOpacity(0.24),
                    ],
                    stops: const [0.0, 0.48, 1.0],
                  ),
                ),
              ),
            ),
            // Soft center glow.
            IgnorePointer(
              child: DecoratedBox(
                decoration: BoxDecoration(
                  gradient: RadialGradient(
                    center: Alignment.center,
                    radius: 0.72,
                    colors: [
                      const Color(0xFF66D1FF).withOpacity(pulse),
                      const Color(0xFFEA57FF).withOpacity(pulse * 0.55),
                      Colors.transparent,
                    ],
                    stops: const [0.0, 0.48, 1.0],
                  ),
                ),
              ),
            ),
            // Vignette to add depth.
            IgnorePointer(
              child: DecoratedBox(
                decoration: BoxDecoration(
                  gradient: RadialGradient(
                    center: Alignment.center,
                    radius: 1.05,
                    colors: [
                      Colors.transparent,
                      const Color(0xCC05070B).withOpacity(0.45),
                    ],
                    stops: const [0.62, 1.0],
                  ),
                ),
              ),
            ),
          ],
        );
      },
    );
  }

  @override
  void dispose() {
    _ticker?.cancel();
    _tableChannel?.unsubscribe();
    _playersChannel?.unsubscribe();
    _chatChannel?.unsubscribe();
    _discardChannel?.unsubscribe();
    _tablePoll?.cancel();
    _playersPoll?.cancel();
    for (final t in _avatarChatTimers.values) {
      t.cancel();
    }
    _avatarChatTimers.clear();
    _chatController.dispose();
    _player.dispose();
    _tileSfxPlayer.dispose();
    _startGameSfxPlayer.dispose();
    _audioPlayer.dispose();
    _hourglassCtrl.dispose();
    _voiceFeedbackTimer?.cancel();
    _voiceCommands.removeListener(_onVoiceCommandsChanged);
    _voiceCommands.dispose();
    WidgetsBinding.instance.removeObserver(this);
    super.dispose();
  }

  Future<void> _bootstrap() async {
    await FeedbackSettingsService.load();
    await _loadTable();
    await _loadPlayers();
    await _loadDiscardHistory();
  }

  void _subscribeRealtime() {
    _tableChannel?.unsubscribe();
    _tableChannel = _supabase
        .channel('okey_screen_table_${widget.tableId}')
        .onPostgresChanges(
          event: PostgresChangeEvent.update,
          schema: 'public',
          table: 'tables',
          filter: PostgresChangeFilter(
            type: PostgresChangeFilterType.eq,
            column: 'id',
            value: widget.tableId,
          ),
          callback: (_) => _loadTable(),
        )
        .subscribe();

    _playersChannel?.unsubscribe();
    _playersChannel = _supabase
        .channel('okey_screen_players_${widget.tableId}')
        .onPostgresChanges(
          event: PostgresChangeEvent.all,
          schema: 'public',
          table: 'table_players',
          filter: PostgresChangeFilter(
            type: PostgresChangeFilterType.eq,
            column: 'table_id',
            value: widget.tableId,
          ),
          callback: (_) => _loadPlayers(),
        )
        .subscribe();

    _discardChannel?.unsubscribe();
    _discardChannel = _supabase
        .channel('okey_screen_discards_${widget.tableId}')
        .onPostgresChanges(
          event: PostgresChangeEvent.all,
          schema: 'public',
          table: 'table_discards',
          filter: PostgresChangeFilter(
            type: PostgresChangeFilterType.eq,
            column: 'table_id',
            value: widget.tableId,
          ),
          callback: (_) => _loadDiscardHistory(),
        )
        .subscribe();

    _chatChannel = _supabase
        .channel('okey_screen_chat_${widget.tableId}')
        .onPostgresChanges(
