  void _playMessageSound() {
    if (FeedbackSettingsService.soundEnabled) {
      _player.play(jo.AssetSource('sounds/message.mp3'));
    }
    FeedbackSettingsService.triggerHaptic();
  }

  DateTime? _lastTileSound;

  void _playTileSfx() {
    if (!FeedbackSettingsService.soundEnabled) return;

    final now = DateTime.now();

    if (_lastTileSound != null &&
        now.difference(_lastTileSound!) < Duration(milliseconds: 80)) {
      return;
    }

    _lastTileSound = now;

    _tileSfxPlayer.stop();
    _tileSfxPlayer.play(jo.AssetSource('sounds/drop.mp3'), volume: 0.35);

    FeedbackSettingsService.triggerHaptic();
  }

  void _playStartGameSfx() {
    if (!FeedbackSettingsService.soundEnabled) return;
    _startGameSfxPlayer.stop();
    _startGameSfxPlayer.play(
      jo.AssetSource('sounds/start_game.wav'),
      volume: 0.55,
    );
  }

  void _scrollToBottom() {
    Future.delayed(const Duration(milliseconds: 50), () {
      if (_chatScroll.hasClients) {
        _chatScroll.animateTo(
          _chatScroll.position.maxScrollExtent,
          duration: const Duration(milliseconds: 300),
          curve: Curves.easeOut,
        );
      }
    });
  }

  String _shortText(String text, {int max = 40}) {
    if (text.length <= max) return text;
    return '${text.substring(0, max)}...';
  }

  Widget _buildMessageBanner() {
    final msg = _lastIncomingMessage!;

    final name = (msg['users']?['username'] ?? 'İzleyici').toString();
    final role = (msg['role'] ?? 'spectator').toString();
    final type = msg['type'] ?? 'text';
    String text;
    IconData icon;

    if (type == 'voice') {
      text = "Sesli mesaj";
      icon = Icons.mic;
    } else {
      text = _shortText(msg['content'] ?? '');
      icon = Icons.chat_bubble;
    }

    return Container(
      padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
      decoration: BoxDecoration(
        gradient: const LinearGradient(
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
