              border: Border.all(color: const Color(0xB36F511D)),
            ),
            child: Icon(icon, color: const Color(0xFF1C2924), size: 17),
          ),
          const SizedBox(width: 10),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
