  bool _openFinishFromTableRow(
    Map<String, dynamic> row,
    String winnerName,
    bool isWinner,
  ) {
    final rawSlots = row['last_final_slots'];
    final rawFinishTile = row['last_finish_tile'];
    if (rawSlots == null || rawSlots is! List || rawFinishTile == null) {
      return false;
    }

    final slots = List<Map<String, dynamic>>.from(rawSlots);
    final finishTile = Map<String, dynamic>.from(
      rawFinishTile as Map<dynamic, dynamic>,
    );
    final winAmount = (row['last_win_amount'] as num?)?.toInt() ?? 0;
    final isDraw = ((row['pot_amount'] as num?)?.toInt() ?? 1) == 0;

    _game.showFinishFromGame(
      slots,
      finishTile,
      winnerName,
      isWinner,
      false,
      winAmount,
      isDraw,
      false,
    );

    setState(() {
      _finishSlots = slots;
      _showFinish = true;
    });
    _autoCloseFinish();
    return true;
  }

  Future<void> _autoCloseFinish() async {
    await Future.delayed(const Duration(milliseconds: 4000));

    if (!mounted) return;
    _game.hideFinish();
    _showFinish = false;
    setState(() {});
  }

  Future<void> _loadTable() async {
    try {
      final row = await _supabase
          .from('tables')
          .select(
            'status,max_players,ready_since,last_finish_at,last_winner_user_id,chat_enabled,spectators_enabled,last_final_slots,last_finish_tile,last_win_amount,pot_amount',
          )
          .eq('id', widget.tableId)
          .maybeSingle();

      if (row == null) return;

      final status = row['status']?.toString() ?? 'waiting';
      final maxPlayers = (row['max_players'] as int?) ?? 2;
      final winner = row['last_winner_user_id']?.toString();
      final readySince = _parseServerTime(row['ready_since']);
      final finishAt = _parseServerTime(row['last_finish_at']);
      final chatEnabled = (row['chat_enabled'] as bool?) ?? true;
      final spectatorsEnabled = (row['spectators_enabled'] as bool?) ?? true;

      final prevFinishAt = _lastFinishAt;
      _tableStatus = status;
      _maxPlayers = maxPlayers;
      _lastFinishAt = finishAt;
      _tableChatEnabled = chatEnabled;
      _tableSpectatorsEnabled = spectatorsEnabled;

      // If a fresh game has started, clear any stale finish overlay state.
      if (_tableStatus == 'playing' && _game.isFinishOpen) {
        _game.hideFinish();
        _showFinish = false;
      }

      _readySince = (_tableStatus == 'waiting' || _tableStatus == 'start')
          ? readySince
          : null;

      if (!_tableChatEnabled && _chatOpen) {
        _chatOpen = false;
        _showEmojiPicker = false;
      }

      final shouldShowFinishFx =
          finishAt != null &&
          (prevFinishAt == null || finishAt.isAfter(prevFinishAt));
      if (shouldShowFinishFx) {
        final winnerName = winner == null
            ? 'Kazanan belli deÄŸil'
            : (_userNames[winner] ?? 'Bir oyuncu');
        _showFinishMessage("$winnerName kazandı");
      }

      if (mounted) setState(() {});
    } catch (e) {
      debugPrint('TABLE LOAD ERROR: $e');
    }
  }

  Future<void> _loadPlayers() async {
    try {
      dynamic rows;
      try {
        rows = await _supabase
            .from('table_players')
            .select('seat_index,user_id,is_double_mode')
            .eq('table_id', widget.tableId)
            .order('seat_index', ascending: true);
      } catch (_) {
        rows = await _supabase
            .from('table_players')
            .select('seat_index,user_id')
            .eq('table_id', widget.tableId)
            .order('seat_index', ascending: true);
      }

      final players = (rows as List)
          .map((e) => Map<String, dynamic>.from(e as Map))
          .toList();

      final currentUserId = _myUserId;
      if (currentUserId != null &&
          !players.any((p) => p['user_id']?.toString() == currentUserId)) {
        _selfMissingStreak++;
        final stillInTable = await _confirmSelfStillInTable(currentUserId);
        if (stillInTable) {
          _selfMissingStreak = 0;
          return;
        }
        // waiting/start anında geçici tutarsızlıklarda asla otomatik çıkma.
        if (_tableStatus == 'waiting' || _tableStatus == 'start') {
          return;
        }
        if (_selfMissingStreak < 4) {
          return;
        }
        _selfMissingStreak = 0;
        if (mounted && !_isLeavingTable) {
          _showSnack('Bağlantı durumu nedeniyle lobiye dönülüyor.');
          _leaveTable();
        }
        return;
      }
      _selfMissingStreak = 0;

      _playerCount = players.length;
      final mySeat = players
          .where((p) => p['user_id']?.toString() == _myUserId)
          .map((p) => p['seat_index'] as int?)
          .cast<int?>()
          .firstWhere((v) => v != null, orElse: () => null);
      _mySeatIndex = mySeat;
      final myRow = players.cast<Map<String, dynamic>?>().firstWhere(
        (p) => p != null && p['user_id']?.toString() == _myUserId,
        orElse: () => null,
      );
      _doubleMode = myRow?['is_double_mode'] == true;

      if (_tableStatus == 'waiting' && _playerCount >= _maxPlayers) {
        _readySince ??= DateTime.now();
      } else {
        _readySince = null;
      }

      final ids = players
          .map((e) => e['user_id']?.toString())
          .whereType<String>()
          .where((e) => e.isNotEmpty)
          .toSet()
          .toList();

      if (ids.isNotEmpty) {
        final rows = await _supabase
            .from('users')
            .select('id,username,email')
            .inFilter('id', ids);
        for (final raw in (rows as List)) {
          final row = Map<String, dynamic>.from(raw as Map);
          final id = row['id']?.toString();
          if (id == null || id.isEmpty) continue;
          final username = row['username']?.toString().trim();
          final email = row['email']?.toString().trim();
          _userNames[id] = (username != null && username.isNotEmpty)
              ? username
              : (email ?? 'Oyuncu');
        }
      }

      if (mounted) setState(() {});
    } catch (e) {
      debugPrint('PLAYER LOAD ERROR: $e');
    }
  }

  Future<void> _loadDiscardHistory() async {
    try {
      final rows = await _supabase
          .from('table_discards')
