  Future<void> _leaveTable() async {
    if (_isLeavingTable) return;
    final userId = _myUserId;
    if (userId == null) return;
    _isLeavingTable = true;

    try {
      _tableChannel?.unsubscribe();
      _playersChannel?.unsubscribe();
      _discardChannel?.unsubscribe();

      await _supabase.rpc(
        'leave_table',
        params: {'p_table_id': widget.tableId, 'p_user_id': userId},
      );

      // ğŸ”¥ DB'nin oturmasÄ±nÄ± bekle
      await _waitUntilPlayerRemoved();

      await _cleanupTableIfInactive();

      _game.resetGameState();

      if (!mounted) return;

      Navigator.of(context).pushAndRemoveUntil(
        MaterialPageRoute(builder: (_) => const LobbyScreen()),
        (route) => false,
      );
    } catch (e) {
      _isLeavingTable = false;
      _showSnack('Masadan ayr\u0131lamad\u0131: $e');
    }
  }

  Future<void> _waitUntilPlayerRemoved() async {
    for (int i = 0; i < 5; i++) {
      final res = await _supabase
          .from('table_players')
          .select('user_id')
          .eq('table_id', widget.tableId);

      final players = (res as List)
          .map((e) => e['user_id']?.toString())
          .toList();

      if (!players.contains(_myUserId)) {
        return; // artÄ±k DB gÃ¼ncel
      }

      await Future.delayed(const Duration(milliseconds: 100));
    }
  }

  Future<void> _cleanupTableIfInactive() async {
    try {
      final playerRows = await _supabase
          .from('table_players')
          .select('user_id')
          .eq('table_id', widget.tableId);

      final players = (playerRows as List)
          .map((e) => Map<String, dynamic>.from(e as Map))
          .toList();

      // ğŸ”¥ 1. HiÃ§ oyuncu yok
      if (players.isEmpty) {
        await _deleteTable();
        return;
      }

      final ids = players
          .map((p) => p['user_id']?.toString())
          .whereType<String>()
          .where((id) => id.isNotEmpty)
          .toList();

      // ğŸ”¥ 2. Bot kontrolÃ¼
      final users = await _supabase
          .from('users')
          .select('id,is_bot')
          .inFilter('id', ids);

      final isBotById = <String, bool>{
        for (final raw in (users as List))
          (raw['id']?.toString() ?? ''): raw['is_bot'] == true,
      };

      final hasHuman = ids.any((id) => isBotById[id] != true);

      // ğŸ”¥ 3. Sadece bot varsa sil
      if (!hasHuman) {
        await _deleteTable();
      }
    } catch (e) {
      debugPrint("cleanup error: $e");
    }
  }

  Future<void> _deleteTable() async {
    try {
      await _supabase
          .from('match_moves')
          .delete()
          .eq('table_id', widget.tableId);
    } catch (_) {}

    try {
      await _supabase
          .from('table_discards')
          .delete()
          .eq('table_id', widget.tableId);
    } catch (_) {}

    try {
      await _supabase
          .from('table_players')
          .delete()
          .eq('table_id', widget.tableId);
    } catch (_) {}

    try {
      await _supabase.from('tables').delete().eq('id', widget.tableId);
    } catch (_) {}
  }

  void _showFinishMessage(String text) {
    _finishFxText = text;
    _showFinishFx = true;
    if (mounted) setState(() {});
    Timer(const Duration(seconds: 3), () {
      if (!mounted) return;
      setState(() => _showFinishFx = false);
    });
  }

  DateTime? _parseServerTime(dynamic raw) {
    if (raw == null) return null;
    final parsed = DateTime.tryParse(raw.toString());
    if (parsed == null) return null;
    return parsed.toLocal();
  }

  int get _joinCountdown {
    if ((_tableStatus != 'waiting' && _tableStatus != 'start') ||
        _playerCount < _maxPlayers) {
      return 0;
    }
    if (_readySince == null) return 0;
    final elapsed = DateTime.now().difference(_readySince!).inSeconds;
    final remain = 5 - elapsed;
    if (remain <= 0) return 0;
    return remain;
  }

