          borderRadius: BorderRadius.circular(18),
          border: Border.all(color: const Color(0x88DAB971), width: 1.1),
          boxShadow: const [
            BoxShadow(
              color: Color(0x4D000000),
              blurRadius: 12,
              offset: Offset(0, 4),
            ),
          ],
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
