  Widget _buildVoiceCommandHud() {
    final listening = _voiceCommands.isListening;
    final executing = _voiceCommands.isExecuting;
    final feedback = _voiceCommands.feedback;
    if (!listening &&
        !executing &&
        feedback == null &&
        !_voiceCommands.isSessionActive) {
      return const SizedBox.shrink();
    }

    final isError = feedback?.isError == true;
    final text =
        feedback?.message ??
        (executing ? 'Komut işleniyor...' : 'Dinlemeye başladım');

    return Positioned(
      left: 12,
      top: 76,
      child: IgnorePointer(
        child: AnimatedContainer(
          duration: const Duration(milliseconds: 180),
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
          constraints: const BoxConstraints(maxWidth: 320),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(14),
            color: const Color(0xDD0E1310),
            border: Border.all(
              color: isError
                  ? const Color(0xCCFF6B6B)
                  : const Color(0xCC7DD19B),
            ),
            boxShadow: const [
              BoxShadow(
                color: Color(0x66000000),
                blurRadius: 14,
                offset: Offset(0, 4),
              ),
            ],
          ),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                isError ? Icons.error_outline : Icons.record_voice_over_rounded,
                color: isError
                    ? const Color(0xFFFF8A80)
                    : const Color(0xFF9AF3B9),
                size: 16,
              ),
              const SizedBox(width: 8),
              Flexible(
                child: Text(
                  text,
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                  style: const TextStyle(
                    color: Colors.white,
                    fontSize: 12.5,
                    fontWeight: FontWeight.w600,
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  Future<bool> _confirmSelfStillInTable(String userId) async {
    try {
      final row = await _supabase
          .from('table_players')
          .select('user_id')
          .eq('table_id', widget.tableId)
          .eq('user_id', userId)
          .maybeSingle();
      return row != null;
    } catch (_) {
      return true;
    }
  }

  void _showIndicatorRewardFxBanner(int amount) {
    if (!mounted || amount <= 0) return;
    setState(() {
      _indicatorRewardAmount = amount;
      _showIndicatorRewardFx = true;
    });
    Future.delayed(const Duration(milliseconds: 1800), () {
      if (!mounted) return;
      setState(() => _showIndicatorRewardFx = false);
    });
  }

