  IconData _leagueIcon(String id) {
    switch (id) {
      case 'standard':
        return Icons.star;
      case 'bronze':
        return Icons.extension; // puzzle hissi
      case 'silver':
        return Icons.build; // kalfa
      case 'gold':
        return Icons.workspace_premium; // usta
      case 'elite':
        return Icons.emoji_events; // ÅŸampiyon
      default:
        return Icons.circle;
    }
  }

  Widget _topCircleButton({
    IconData? icon,
    String? asset,
    bool active = false,
    bool highlight = false,
    int? type,
    required VoidCallback onTap,
  }) {
    final isExit = icon == Icons.logout || icon == Icons.exit_to_app;

    /// ğŸ”¥ ICON SEÃ‡Ä°MÄ° (Ã¶ncelik sÄ±rasÄ± Ã¶nemli)
    Widget iconWidget;

    if (type != null) {
      iconWidget = buildActionIcon(type); // ğŸ‘ˆ senin metod
    } else if (asset != null) {
      iconWidget = Image.asset(asset, width: 22, height: 22);
    } else if (icon != null) {
      iconWidget = Icon(
        icon,
        size: 20,
        color: isExit ? Colors.redAccent : Colors.white70,
      );
    } else {
      iconWidget = const SizedBox(); // ğŸ‘ˆ null crash Ã¶nler
    }

    return Material(
      color: Colors.transparent,
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(999),
        child: Container(
          width: 42,
          height: 42,
          decoration: BoxDecoration(
            shape: BoxShape.circle,

            /// ğŸ”¥ EXIT STYLE
            color: isExit
                ? const Color(0xFF3A1F1F)
                : (active ? const Color(0xFF2A3440) : const Color(0xCC0F141A)),

            border: Border.all(
              color: isExit
                  ? Colors.red.withOpacity(0.6)
                  : (highlight
                        ? Colors.amber.withOpacity(0.8) // ğŸ‘ˆ highlight aktif
                        : const Color.fromARGB(102, 134, 131, 126)),
              width: 0.9,
            ),

            boxShadow: [
              if (isExit)
                BoxShadow(color: Colors.red.withOpacity(0.4), blurRadius: 8),

              /// ğŸ”¥ highlight glow (premium)
              if (highlight && !isExit)
                BoxShadow(color: Colors.amber.withOpacity(0.4), blurRadius: 10),
            ],
          ),
          child: Center(child: iconWidget),
        ),
      ),
    );
  }

  Widget buildActionIcon(int type) {
    final color = Colors.amber;

    switch (type) {
      /// 1ï¸âƒ£ SERÄ° DÄ°Z â†’ yan yana
      case 0:
        return Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            _tile("1", color),
            const SizedBox(width: 2),
            _tile("2", color),
          ],
        );

      /// 2ï¸âƒ£ Ã‡Ä°FTE DÄ°Z â†’ Ã¼st Ã¼ste (stack)
      case 1:
        return SizedBox(
          width: 22,
          height: 20,
          child: Stack(
            alignment: Alignment.center,
            children: [
              Positioned(left: 2, child: _tile("1", color)),
              Positioned(left: 8, child: _tile("2", color)),
            ],
          ),
        );

      /// 3ï¸âƒ£ Ã‡Ä°FTE GÄ°T â†’ Ã¼st Ã¼ste + ok
      case 2:
        return Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            SizedBox(
              width: 22,
              height: 18,
              child: Stack(
                alignment: Alignment.center,
                children: [
                  Positioned(left: 2, child: _tile("1", color)),
                  Positioned(left: 8, child: _tile("2", color)),
                ],
              ),
            ),
            const SizedBox(height: 2),
            Icon(Icons.arrow_downward, size: 12, color: color),
          ],
        );

      default:
        return const SizedBox();
    }
  }

