  Widget _buildWaitingOverlay() {
    final full = _playerCount >= _maxPlayers;
    final gameCount = _game.getCountdown();
    final count = gameCount > 0
        ? gameCount
        : (_tableStatus == 'start' ? 0 : _joinCountdown);

    final text = full
        ? (count > 0
              ? 'Oyun $count saniye sonra başlayacak...'
              : 'Oyun başlatılıyor...')
        : 'Oyuncu bekleniyor...';

    return IgnorePointer(
      ignoring: true,
      child: Align(
        alignment: Alignment.center,
        child: ClipRRect(
          borderRadius: BorderRadius.circular(24),
          child: BackdropFilter(
            filter: ImageFilter.blur(sigmaX: 6, sigmaY: 6),
            child: Container(
              width: 430,
              padding: const EdgeInsets.fromLTRB(24, 18, 24, 18),
              decoration: BoxDecoration(
                gradient: const LinearGradient(
                  begin: Alignment.topLeft,
                  end: Alignment.bottomRight,
                  colors: [Color(0xA01A2722), Color(0xA0101713)],
                ),
                borderRadius: BorderRadius.circular(24),
                border: Border.all(color: const Color(0x88A8C2B1), width: 1.15),
                boxShadow: [
                  BoxShadow(
                    color: const Color(0xFF000000).withOpacity(0.5),
                    blurRadius: 24,
                    offset: const Offset(0, 9),
                  ),
                  BoxShadow(
                    color: const Color(0x667EA399).withOpacity(0.2),
                    blurRadius: 18,
                    spreadRadius: 0.5,
                  ),
                ],
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  if (full && count > 0)
                    ScaleTransition(
                      scale: Tween(begin: 0.95, end: 1.04).animate(
                        CurvedAnimation(
                          parent: _hourglassCtrl,
                          curve: Curves.easeInOut,
                        ),
                      ),
                      child: Container(
                        width: 64,
                        height: 64,
                        decoration: BoxDecoration(
                          shape: BoxShape.circle,
                          gradient: const RadialGradient(
                            center: Alignment(-0.2, -0.25),
                            radius: 0.95,
                            colors: [Color(0xFFD8E8E0), Color(0xFF6E8F84)],
                          ),
                          border: Border.all(
                            color: const Color(0xFFEAF4EF),
                            width: 1.2,
                          ),
                          boxShadow: [
                            BoxShadow(
                              color: const Color(0xAA0E1D19).withOpacity(0.55),
                              blurRadius: 12,
                              offset: const Offset(0, 4),
                            ),
                          ],
                        ),
                        child: Center(
                          child: Text(
                            '$count',
                            style: const TextStyle(
                              fontFamily: "Orbitron",
                              color: Color(0xFF123028),
                              fontSize: 26,
                              fontWeight: FontWeight.w900,
                            ),
                          ),
                        ),
                      ),
                    )
                  else
                    ScaleTransition(
                      scale: Tween(begin: 0.92, end: 1.08).animate(
                        CurvedAnimation(
                          parent: _hourglassCtrl,
                          curve: Curves.easeInOut,
                        ),
                      ),
                      child: const Icon(
                        Icons.hourglass_top_rounded,
                        color: Color(0xFFE7D3AB),
                        size: 34,
                      ),
                    ),
                  const SizedBox(height: 10),
                  Text(
                    text,
                    textAlign: TextAlign.center,
                    style: const TextStyle(
                      fontFamily: "Montserrat",
                      fontWeight: FontWeight.w800,
                      fontSize: 18,
                      letterSpacing: 0.25,
                      color: Color(0xFFF3F1E8),
                    ),
                  ),
                  const SizedBox(height: 6),
                  if (!full)
                    const Text(
                      "Diğer oyuncuları davet ederek oyunu hızlandırabilirsin",
                      textAlign: TextAlign.center,
                      style: TextStyle(
                        fontFamily: "Montserrat",
                        fontWeight: FontWeight.w500,
                        fontSize: 12.5,
                        color: Color(0xB3D8D2C4),
                      ),
                    ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

