            Positioned(
              left: pos.dx,
              top: pos.dy + size.height + 6,
              child: QuickChatMenu(
                onSelect: (msg) {
                  if (msg == "__CHAT__") {
                    if (_tableChatEnabled) {
                      setState(() {
                        _chatOpen = true;
                        _showEmojiPicker = false;
                      });
                    }
                  } else {
                    _chatController.text = msg;
                    _sendMessage();
                  }

                  _closeQuickChat();
                },
              ),
            ),
          ],
        );
      },
    );

    Overlay.of(context).insert(_quickChatOverlay!);
  }

  void _closeQuickChat() {
    _quickChatOverlay?.remove();
    _quickChatOverlay = null;
  }
}

class DoubleConfirmDialog extends StatelessWidget {
  final OkeyGame game;

  const DoubleConfirmDialog({super.key, required this.game});

  @override
  Widget build(BuildContext context) {
    return Stack(
      children: [
        /// ğŸ”¥ BACKDROP BLUR
        Positioned.fill(
          child: GestureDetector(
            onTap: () {},
            child: BackdropFilter(
              filter: ImageFilter.blur(sigmaX: 6, sigmaY: 6),
              child: Container(color: Colors.black.withOpacity(0.5)),
            ),
          ),
        ),

        /// ğŸ”¥ CENTER PANEL
        Center(
          child: Container(
            width: 320,
            padding: const EdgeInsets.all(20),
            decoration: BoxDecoration(
              borderRadius: BorderRadius.circular(20),
              gradient: LinearGradient(
                colors: [Color(0xFF1A1A1A), Color(0xFF0F0F0F)],
                begin: Alignment.topLeft,
                end: Alignment.bottomRight,
              ),
              border: Border.all(color: Color(0xFFE7C66A).withOpacity(0.5)),
              boxShadow: [
                BoxShadow(
                  color: Color(0xFFE7C66A).withOpacity(0.25),
                  blurRadius: 30,
                ),
              ],
            ),

            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                /// TITLE
                Row(
                  children: const [
                    Icon(Icons.warning_amber_rounded, color: Color(0xFFE7C66A)),
                    SizedBox(width: 8),
                    Text(
                      "Çifte Git",
                      style: TextStyle(
                        color: Colors.white,
                        fontSize: 18,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                  ],
                ),

                const SizedBox(height: 16),

                const Text(
                  "Bu kararı geri alamazsın.\nÇiftten bitmek zorundasın.",
                  style: TextStyle(color: Colors.white70, height: 1.4),
                ),

                const SizedBox(height: 20),

                Row(
                  children: [
                    Expanded(
                      child: OutlinedButton(
                        onPressed: () => game.overlays.remove('DoubleConfirm'),
                        child: const Text("Hayır"),
                      ),
                    ),
                    const SizedBox(width: 10),
                    Expanded(
                      child: ElevatedButton(
                        style: ElevatedButton.styleFrom(
                          backgroundColor: Color(0xFFE7C66A),
                          foregroundColor: Colors.black,
                        ),
                        onPressed: () async {
                          game.overlays.remove('DoubleConfirm');
                          await game.confirmDoubleMode();
                        },
                        child: const Text("Evet"),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
        ),
      ],
    );
  }
}
